#!/usr/bin/env python3import fontforgeimport osimport sysimport tempfilefrom typing import Optionaldef main():    sys.stdout.buffer.write(do_generate_font())def do_generate_font() -&gt; bytes:    fd, fn = tempfile.mkstemp(suffix=&quot;.ttf&quot;)    os.close(fd)    font = fontforge.font()    font.copyright = &quot;DUMMY FONT&quot;    font.generate(fn)    with open(fn, &quot;rb&quot;) as f:        res = f.read()    os.unlink(fn)    result = res    return resultif __name__ == &quot;__main__&quot;:    main()
