package mainimport (	&quot;fmt&quot;	&quot;hash/crc32&quot;	&quot;io&quot;	&quot;io/fs&quot;	&quot;net/http&quot;	&quot;os&quot;	&quot;time&quot;	&quot;github.com/flamego/flamego&quot;	&quot;github.com/go-redis/redis/v8&quot;	&quot;org.d3ctf.app/static&quot;)func crc32Hash(str string) string &#123;	return fmt.Sprint(crc32.ChecksumIEEE([]byte(str)))&#125;func main() &#123;	f := flamego.Classic()	f.Map(		Cache&#123;			client: redis.NewClient(&amp;redis.Options&#123;				Addr: os.ExpandEnv(&quot;127.0.0.1:6379&quot;),			&#125;),		&#125;,	)	staticFS, _ := fs.Sub(static.FS, &quot;dist&quot;)	f.Use(flamego.Static(flamego.StaticOptions&#123;		FileSystem: http.FS(staticFS),	&#125;))	f.Get(&quot;/fetch&quot;, func(ctx flamego.Context, cache Cache, r *http.Request, rw http.ResponseWriter) &#123;		url := ctx.Query(&quot;url&quot;)		cacheKey := crc32Hash(url)		fmt.Println(cacheKey)		if buf, err := cache.Get(r.Context(), cacheKey); err == nil &#123;			ctx.ResponseWriter().Write(buf)			return		&#125;		resp, _ := http.Get(url)		buf, _ := io.ReadAll(resp.Body)		cache.Set(r.Context(), cacheKey, buf, time.Minute*10)		rw.Write(buf)	&#125;)	f.Run()&#125;
tomcat服务三个服务对应3个URL，首先看go吧，这其实就是一个简单的redis缓存服务，会将一个键值对储存进Redis服务器，然后注意tomcat服务器，它里面用到了一个依赖（圈起来了）redis-session-manager这个依赖，而这个依赖是如何运作的呢？它会从redis去除键名为JSESSION的值，然后反序列化它，对应tomcat.request.session.redis.SessionManager#findSession方法：
public Session findSession(String sessionId) throws IOException &#123;        if (sessionId != null &amp;&amp; this.sessionContext.get() != null &amp;&amp; sessionId.equals(((SessionContext)this.sessionContext.get()).getId())) &#123;            return ((SessionContext)this.sessionContext.get()).getSession();        &#125; else &#123;            Session session = null;            boolean isPersisted = false;            SessionMetadata metadata = null;            byte[] data = this.dataCache.get(sessionId);            if (data == null) &#123;                sessionId = null;                isPersisted = false;            &#125; else &#123;                if (Arrays.equals(SessionConstants.NULL_SESSION, data)) &#123;                    throw new IOException(&quot;NULL session data&quot;);                &#125;                try &#123;                    metadata = new SessionMetadata();                    Session newSession = this.createEmptySession();                    //反序列化session                    this.serializer.deserializeSessionData(data, newSession, metadata);                    newSession.setId(sessionId);                    newSession.access();                    newSession.setNew(false);                    newSession.setValid(true);                    newSession.resetDirtyTracking();                    newSession.setMaxInactiveInterval(this.getSessionTimeout(newSession));                    session = newSession;                    isPersisted = true;                &#125; catch (Exception var7) &#123;                    LOGGER.error(&quot;Error occurred while de-serializing the session object..&quot;, var7);                &#125;            &#125;            this.setValues(sessionId, session, isPersisted, metadata);            return session;        &#125;    &#125;
调用了deserializeSessionData去反序列化，而里面又调用了readObject：并且题目中的pom文件是给了CC依赖的，因此不难联想到往redis缓存投入一个恶意binary数据，然后通过这个去反序列化从而RCE。然后再审一下go源码，go源码做的事情就是访问一个URL，然后通过crc32Hash方法去计算这个URL的CRC，并且作为键名储存进redis，键值为访问返回的数据大概是这样子的一个服务，那么思路也就很清晰，先让go去缓存一下我们的恶意文件，获取序列化数据储存进redis，我们本地起一个题目源码去获取crc数据，然后把JSESSIONID改为crc的值，那么当我们去发包时，就会反序列化触发rce。接下来给出具体步骤我们的payload如下
