String类常用方法    package com.boogipop.www.base;    import java.util.Arrays;    public class Main &#123;        public static void main(String[] args) &#123;//常用方法            String str=&quot;php in the best langeuage php best&quot;;            //获得字符串长度            System.out.println(str.length()); //25            //获取指定字符            System.out.println(str.charAt(str.length()-1)); //e            //判断是否包含指定字符            System.out.println(str.contains(&quot;php&quot;)); //true            //toCharArray;返回字符串对应数组            //indexOf;返回字符串首次出现位置            //lastIndexOf;返回字符串最后一次出现的位置            System.out.println(Arrays.toString(str.toCharArray()));//Arrays.toString将数组变为字符串            //[p, h, p,  , i, n,  , t, h, e,  , b, e, s, t,  , l, a, n, g, e, u, a, g, e,  , p, h, p,  , b, e, s, t]            System.out.println(str.indexOf(&quot;php&quot;));            //0            System.out.println(str.indexOf(&quot;php&quot;,4));//设置起始位置            //26            System.out.println(str.lastIndexOf(&quot;best&quot;));//30            //trim去除字符串前后空格            //toUppercase转大写            //toLowercase转小写            //endwith判断是否以。。。结尾            //startwith判断是否以。。。开头            String str2=&quot;  Boogipop   &quot;;            System.out.println(str2.trim()); //Boogipop            System.out.println(str2.toUpperCase());//  BOOGIPOP            System.out.println(str2.toLowerCase());//  boogipop            System.out.println(str2.endsWith(&quot; &quot;));//true            System.out.println(str2.endsWith(&quot; &quot;));//true            //replace 替换            //split 拆分            String str3=&quot;i am the best,XIXI&quot;;            System.out.println(str3.replace(&quot;best&quot;,&quot;worst&quot;)); //i am the worst            System.out.println(Arrays.toString(str3.split(&quot; &quot;)));//[i, am, the, best]            //里面有一个逗号，加入我们想让他以空格或者逗号拆分怎么办            System.out.println(Arrays.toString(str3.split(&quot;[ ,]&quot;)));//正则        &#125;    &#125;
