1X1.6.5 Unsafe加载字节码import sun.misc.Unsafe;import java.lang.reflect.Field;import java.lang.reflect.Method;import java.nio.file.Files;import java.nio.file.Paths;public class Test &#123;    public static void main(String[] args) throws Exception &#123;        byte[] words= Files.readAllBytes(Paths.get(&quot;E:\\CTF学习笔记\\Java\\Java\\out\\production\\Java\\Hello.class&quot;));        ClassLoader c=ClassLoader.getSystemClassLoader();        Field f=Unsafe.class.getDeclaredField(&quot;theUnsafe&quot;);        f.setAccessible(true);        Unsafe unsafe = (Unsafe) f.get(null);        Class&lt;?&gt; hello = unsafe.defineClass(&quot;Hello&quot;, words, 0, words.length, c, null);        hello.newInstance();    &#125;&#125;
