RPC协议RPC全称为Remote Procedure Call Protocol（远程调用协议），RPC和之前学的RMI十分类似，都是远程调用服务，它们不同之处就是RPC是通过标准的二进制格式来定义请求的信息，这样跨平台和系统就更加方便RPC协议的一次远程通信过程如下

客户端发起请求，并按照RPC协议格式填充信息
填充完毕后将二进制格式文件转化为流，通过传输协议进行传输
服务端接收到流后，将其转换为二进制格式文件，并按照RPC协议格式获取请求的信息并进行处理
处理完毕后将结果按照RPC协议格式写入二进制格式文件中并返回

Hessian协议Hessian是一个基于RPC的高性能二进制远程传输协议，官方对Java、Python、C++……语言都进行了实现，Hessian一般在Web服务中使用，在Java里它的使用方法很简单，它定义远程对象，并通过二进制的格式进行传输。
Hessian基本使用&lt;dependency&gt;    &lt;groupId&gt;com.caucho&lt;/groupId&gt;    &lt;artifactId&gt;hessian&lt;/artifactId&gt;    &lt;version&gt;4.0.63&lt;/version&gt;&lt;/dependency&gt;
import java.io.Serializable; public class Person implements Serializable &#123;    public String name;    public int age;     public int getAge() &#123;        return age;    &#125;     public String getName() &#123;        return name;    &#125;     public void setAge(int age) &#123;        this.age = age;    &#125;     public void setName(String name) &#123;        this.name = name;    &#125;&#125;
import com.caucho.hessian.io.HessianInput;import com.caucho.hessian.io.HessianOutput; import java.io.ByteArrayInputStream;import java.io.ByteArrayOutputStream;import java.io.IOException;import java.io.Serializable; public class Hessian_Test implements Serializable &#123;     public static &lt;T&gt; byte[] serialize(T o) throws IOException &#123;        ByteArrayOutputStream bao = new ByteArrayOutputStream();        HessianOutput output = new HessianOutput(bao);        output.writeObject(o);        System.out.println(bao.toString());        return bao.toByteArray();    &#125;     public static &lt;T&gt; T deserialize(byte[] bytes) throws IOException &#123;        ByteArrayInputStream bai = new ByteArrayInputStream(bytes);        HessianInput input = new HessianInput(bai);        Object o = input.readObject();        return (T) o;    &#125;     public static void main(String[] args) throws IOException &#123;        Person person = new Person();        person.setAge(18);        person.setName(&quot;Feng&quot;);         byte[] s = serialize(person);        System.out.println((Person) deserialize(s));    &#125; &#125;
Java原生反序列化：
import java.io.*; public class Ser_Test implements Serializable &#123;     public static &lt;T&gt; byte[] serialize(T t) throws IOException &#123;        ByteArrayOutputStream bao = new ByteArrayOutputStream();        ObjectOutputStream oos = new ObjectOutputStream(bao);        oos.writeObject(t);        System.out.println(bao.toString());        return bao.toByteArray();    &#125;     public static &lt;T&gt; T deserialize(byte[] bytes) throws IOException, ClassNotFoundException &#123;        ByteArrayInputStream bai = new ByteArrayInputStream(bytes);        ObjectInputStream ois  =new ObjectInputStream(bai);        return (T) ois.readObject();    &#125;     public static void main(String[] args) throws IOException, ClassNotFoundException &#123;        Person person = new Person();        person.setAge(18);        person.setName(&quot;Feng&quot;);         byte[] s=serialize(person);        System.out.println((Person) deserialize(s));    &#125;&#125;
