package com.supeream.serial;import java.io.*;public class Serializables &#123;    public static byte[] serialize(final Object obj) throws IOException &#123;        final ByteArrayOutputStream out = new ByteArrayOutputStream();        serialize(obj, out);        return out.toByteArray();    &#125;    public static void serialize(final Object obj, final OutputStream out) throws IOException &#123;        final ObjectOutputStream objOut = new ObjectOutputStream(out);        objOut.writeObject(obj);        objOut.flush();        objOut.close();    &#125;    public static Object deserialize(final byte[] serialized) throws IOException, ClassNotFoundException &#123;        final ByteArrayInputStream in = new ByteArrayInputStream(serialized);        return deserialize(in);    &#125;    public static Object deserialize(final InputStream in) throws ClassNotFoundException, IOException &#123;        final ObjectInputStream objIn = new ObjectInputStream(in);        return objIn.readObject();    &#125;&#125;
