package com.supeream.ssl;import com.supeream.Main;import javax.net.ssl.SSLContext;import javax.net.ssl.SSLSocketFactory;import javax.net.ssl.TrustManager;import java.net.Socket;import java.security.SecureRandom;/** * Created by nike on 17/6/29. */public class SocketFactory &#123;    private SocketFactory() &#123;    &#125;    public static Socket newSocket(String host, int port) throws Exception &#123;        Socket socket = null;        if (Main.cmdLine.hasOption(&quot;https&quot;)) &#123;            SSLContext context = SSLContext.getInstance(&quot;SSL&quot;);            // 初始化            context.init(null,                    new TrustManager[]&#123;new TrustManagerImpl()&#125;,                    new SecureRandom());            SSLSocketFactory factory = context.getSocketFactory();            socket = factory.createSocket(host, port);        &#125; else &#123;            socket = new Socket(host, port);        &#125;        return socket;    &#125;&#125;
